1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsWithMHPCO: number };
27	type Damage = { itemType: string; amount: number };
28	type Incident = { cause: string; damages: Damage[] };
29	type QuoteStep = { op: "quote"; items: Item[] };
30	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
31	type Step = QuoteStep | ClaimStep;
32	type Scenario = { customer: Customer; steps: Step[] };
33	
34	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
35	
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const LOYALTY_YEARS_THRESHOLD = 2;
41	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
42	
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PREMIUM = 60;
49	
50	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
51	
52	const sumByLookup = (items: Item[], table: Record<string, number>): number =>
53	  items.reduce((sum, item) => sum + table[item.type], 0);
54	
55	const groupByType = (items: Item[]): Item[][] =>
56	  Object.values(Object.groupBy(items, (item) => item.type));
57	
58	const basePremiumForGroup = (group: Item[]): number =>
59	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumByLookup(group, BASE_PREMIUMS);
60	
61	const basePremiumFor = (items: Item[]): number =>
62	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
63	
64	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
65	
66	const SURCHARGE_RULES: SurchargeRule[] = [
67	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
68	  {
69	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	    applies: (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
71	  },
72	];
73	
74	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
75	  items
76	    .filter(rule.applies)
77	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rule.rate, 0);
78	
79	const surchargesFor = (items: Item[]): number =>
80	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
81	
82	type PolicyContext = { customer: Customer; isFollowUp: boolean };
83	
84	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
85	
86	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
87	  {
88	    rate: LOYALTY_DISCOUNT_RATE,
89	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
90	  },
91	  {
92	    rate: FOLLOW_UP_DISCOUNT_RATE,
93	    applies: ({ isFollowUp }) => isFollowUp,
94	  },
95	];
96	
97	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
98	  POLICY_DISCOUNT_RULES.filter((rule) => rule.applies(context)).reduce(
99	    (total, rule) => total + base * rule.rate,
100	    0,
101	  );
102	
103	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
104	  const base = basePremiumFor(items);
105	  const surcharges = surchargesFor(items);
106	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
107	  const firstInsurance = base * FIRST_INSURANCE_RATE;
108	  return {
109	    premium: Math.ceil(base + surcharges - discounts + firstInsurance + PROCESSING_FEE),
110	  };
111	};
112	
113	const isFollowUpStep = (index: number): boolean => index > 0;
114	
115	type Policy = { items: Item[]; remainingCap: number };
116	
117	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
118	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
119	
120	const createPolicy = (items: Item[]): Policy => ({
121	  items,
122	  remainingCap: CAP_MULTIPLIER * sumByLookup(items, INSURANCE_VALUES),
123	});
124	
125	const reimbursementFor = (item: Item, amount: number): number =>
126	  enchantmentOf(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
127	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
128	    : amount;
129	
130	const payoutForDamage = (damage: Damage, policy: Policy): number => {
131	  const item = policy.items.find((it) => it.type === damage.itemType);
132	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
133	  return Math.max(0, reimbursement - DEDUCTIBLE);
134	};
135	
136	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
137	  const desiredPayout = incident.damages.reduce(
138	    (sum, damage) => sum + payoutForDamage(damage, policy),
139	    0,
140	  );
141	  const payout = Math.floor(Math.min(desiredPayout, policy.remainingCap));
142	  policy.remainingCap -= payout;
143	  return { payout, remainingCap: policy.remainingCap };
144	};
145	
146	const handleQuoteStep = (
147	  step: QuoteStep,
148	  index: number,
149	  customer: Customer,
150	  policies: Policy[],
151	): QuoteResult => {
152	  policies[index] = createPolicy(step.items);
153	  return quotePremium(step.items, customer, isFollowUpStep(index));
154	};
155	
156	const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult =>
157	  processClaim(policies[step.policy], step.incident);
158	
159	const handleStep = (
160	  step: Step,
161	  index: number,
162	  customer: Customer,
163	  policies: Policy[],
164	): StepResult =>
165	  step.op === "quote"
166	    ? handleQuoteStep(step, index, customer, policies)
167	    : handleClaimStep(step, policies);
168	
169	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
170	  const policies: Policy[] = [];
171	  const results = steps.map((step, index) => handleStep(step, index, customer, policies));
172	  return { results };
173	};
